-- supabase/seed/demo_businesses.sql
-- Seed de démo dense : 5 établissements par catégorie (11) x par ville (49
-- villes — 29 en Pyrénées-Atlantiques + 20 dans les Landes)
-- = 2695 lignes. Généré programmatiquement (voir gen-seed.tmp.cjs, non commité).
-- Slugs préfixés "demo-" + catégorie + ville + index, garantis uniques par
-- construction. Nettoyage : DELETE FROM businesses WHERE slug LIKE 'demo-%';
-- Champs non listés restent NULL / valeur par défaut (open_days notamment).

